     2|import type { ImagesManifest } from './images-loader'
     3|import { resolveImage } from './images-loader'
     4|
     5|export interface CopyContext {
     6|  siteContent: Record<string, unknown>
     7|  verticalCopy: Record<string, unknown>
     8|  placeholders: Record<string, string | number | undefined>
     9|  /** Optional images manifest for `@img:` / `@src:` / `$img` expansion. */
    10|  images?: ImagesManifest | null
    11|  /** Locale code — when set, `$img` expansions prefer `altByLocale[locale]`. */
    12|  locale?: string
    13|}
