    15|function getByPath(root: Record<string, unknown>, path: string): unknown {
    16|  return path.split('.').reduce<unknown>((acc, key) => {
    17|    if (acc && typeof acc === 'object') {
    18|      return (acc as Record<string, unknown>)[key]
    19|    }
    20|    return undefined
    21|  }, root)
    22|}
    23|
    24|export function resolveRef(ref: string, ctx: CopyContext): unknown {
    25|  const siteHit = getByPath(ctx.siteContent, ref)
    26|  if (siteHit !== undefined) return followRefs(siteHit, ctx)
    27|  const verticalHit = getByPath(ctx.verticalCopy, ref)
    28|  if (verticalHit !== undefined) return followRefs(verticalHit, ctx)
    29|  return undefined
    30|}
    31|
    32|/**
    33| * Expand an image manifest reference embedded in a string. Content authors
    34| * can write:
    35| *   "@img:hero.home"  → returns `asset.src` (resolved URL)
    36| *   "@src:hero.home"  → alias for `@img:`; same behavior
    37| * Returns `undefined` when the manifest is missing or the key doesn't
    38| * match — callers should leave the raw string in place so the broken ref
    39| * is visible rather than silently dropped.
    40| */
    41|function resolveImageRefString(
    42|  value: string,
    43|  ctx: CopyContext,
    44|): string | undefined {
    45|  if (!ctx.images) return undefined
    46|  let key: string | undefined
    47|  if (value.startsWith('@img:')) key = value.slice(5)
    48|  else if (value.startsWith('@src:')) key = value.slice(5)
    49|  if (!key) return undefined
    50|  // @img/@src only need the `.src` — no locale-aware alt needed here.
    51|  const asset = resolveImage(ctx.images, key)
    52|  return asset ? asset.src : undefined
    53|}
    54|
    55|function followRefs(value: unknown, ctx: CopyContext, depth = 0): unknown {
    56|  if (depth > 10) return value
    57|  if (typeof value === 'string') {
    58|    // `@img:bucket.asset` / `@src:bucket.asset` → resolved src URL. On
    59|    // miss we return the raw string so authors can see the broken ref.
    60|    if (value.startsWith('@img:') || value.startsWith('@src:')) {
    61|      const hit = resolveImageRefString(value, ctx)
    62|      return fillDeep(hit ?? value, ctx.placeholders)
    63|    }
    64|    return fillDeep(value, ctx.placeholders)
    65|  }
    66|  if (value && typeof value === 'object' && !Array.isArray(value)) {
    67|    const rec = value as Record<string, unknown>
    68|    if (typeof rec.$ref === 'string') {
    69|      const resolved = resolveRef(rec.$ref, ctx)
    70|      return resolved !== undefined
    71|        ? followRefs(resolved, ctx, depth + 1)
    72|        : fillDeep(value, ctx.placeholders)
    73|    }
    74|    // `{ $img: "bucket.asset" }` → full ImageAsset object `{ src, alt, ... }`.
    75|    // On miss we leave the object untouched so the broken ref is visible.
    76|    if (typeof rec.$img === 'string' && ctx.images) {
    77|      const asset = resolveImage(ctx.images, rec.$img, ctx.locale)
    78|      if (asset) return { ...asset }
    79|    }
    80|    const out: Record<string, unknown> = {}
    81|    for (const [k, v] of Object.entries(rec)) {
    82|      out[k] = followRefs(v, ctx, depth + 1)
    83|    }
    84|    return fillDeep(out, ctx.placeholders)
    85|  }
    86|  if (Array.isArray(value)) {
    87|    return value.map((v) => followRefs(v, ctx, depth + 1))
    88|  }
    89|  return fillDeep(value, ctx.placeholders)
