{"content": "#!/usr/bin/env python3
"""Check actual src patterns"""
import json, os

BASE = "/tmp/paragu-ai-builder/sites"
srcs = {}

for d in sorted(os.listdir(BASE)):
    if not d.startswith("preview-"): continue
    cp = os.path.join(BASE, d, "content", "es.json")
    if not os.path.exists(cp): continue

    with open(cp) as f:
        content = json.load(f)

    gallery = content.get("home", {}).get("gallery", {})
    images = gallery.get("images", [])

    if not images: continue
    first_src = images[0].get("src", "")
    # Extract pattern
    if "supabase" in first_src:
        pat = "supabase"
    elif "unsplash" in first_src:
        pat = "unsplash"
    elif "photoreference" in first_src:
        pat = "google"
    elif first_src.startswith("/"):
        pat = "local_path"
    elif first_src.startswith("http"):
        pat = "http_other"
    elif first_src.startswith("data:"):
        pat = "data_uri"
    elif first_src == "":
        pat = "empty"
    else:
        pat = "other"

    srcs[pat] = srcs.get(pat, 0) + 1
    if pat == "http_other" and srcs[pat] <= 3:
        print(f"  {d}: {first_src[:120]}")

print(f"\nSummary: {srcs}")
", "path": "/tmp/check_src_patterns.py"}
